#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int D, C; scanf("%d %d", &D, &C);
        int a1,a2,a3,b1,b2,b3; scanf("%d %d %d", &a1, &a2, &a3);
        scanf("%d %d %d", &b1, &b2, &b3);
        int sumA = a1 + a2 + a3;
        int sumB = b1 + b2 + b3;
        int cost_without = sumA + sumB + 2 * D;
        int extra = C;
        if(sumA < 150) extra += D;
        if(sumB < 150) extra += D;
        int cost_with = sumA + sumB + extra;
        if(cost_with < cost_without) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

